// defer = 함수 종료 시 실행 예약
// 여러 개면 스택처럼 역순 실행!
// 인자는 defer 호출 시점에 평가됨

x := 10
defer fmt.Println(x) // 10 출력 (지금 평가!)
x = 20

// 파일 열기 → defer로 닫기 보장!
func ReadFile(path string) ([]byte, error) {
    f, err := os.Open(path)
    if err != nil {
        return nil, err
    }
    defer f.Close() // 함수 끝나면 반드시 닫힘!

    return io.ReadAll(f)
}

// 뮤텍스 잠금 → defer로 해제!
var mu sync.Mutex

func SafeUpdate(data *Data) {
    mu.Lock()
    defer mu.Unlock() // 잠금 해제 보장!

    data.Count++
    data.UpdatedAt = time.Now()
    // 어떤 에러가 나도 Unlock 실행!
}

// panic = 복구 불가능한 심각한 에러!
func MustParseConfig(path string) Config {
    data, err := os.ReadFile(path)
    if err != nil {
        panic("설정 파일 없음: " + path)
    }
    var cfg Config
    if err := json.Unmarshal(data, &cfg);
        err != nil {
        panic("설정 파싱 실패: " + err.Error())
    }
    return cfg
}

// panic 발생 시:
// 1. 현재 함수 즉시 중단
// 2. defer들은 실행됨! ← 중요!
// 3. 호출 스택을 거슬러 올라감
// 4. recover 없으면 프로그램 종료

// ⚠️ 일반 에러는 error 반환 사용!
// panic은 정말 심각할 때만!

// recover = defer 안에서만 동작!
func SafeExecute(fn func()) (err error) {
    defer func() {
        if r := recover(); r != nil {
            err = fmt.Errorf("복구됨: %v", r)
        }
    }()

    fn() // panic이 발생해도 복구!
    return nil
}

// 사용 예시
err := SafeExecute(func() {
    panic("큰일이다!")
})
fmt.Println(err)
// 복구됨: 큰일이다!

// recover() 반환값:
// - panic 인자값 (interface{})
// - panic 없으면 nil

// 고루틴에서 panic → 전체 프로그램 종료!
// recover로 보호하는 패턴
func SafeGo(fn func()) {
    go func() {
        defer func() {
            if r := recover(); r != nil {
                log.Printf("고루틴 패닉: %v",
                    r)
                // 스택 트레이스 출력
                debug.PrintStack()
            }
        }()
        fn()
    }()
}

// HTTP 서버의 미들웨어 패턴
func Recovery(next http.Handler) http.Handler {
    return http.HandlerFunc(
        func(w http.ResponseWriter,
            r *http.Request) {
        defer func() {
            if err := recover(); err != nil {
                w.WriteHeader(500)
            }
        }()
        next.ServeHTTP(w, r)
    })
}

// 실행 시간 측정 패턴
func TrackTime(name string) func() {
    start := time.Now()
    return func() {
        fmt.Printf("%s: %v\n",
            name, time.Since(start))
    }
}

func Process() {
    defer TrackTime("Process")()
    // ... 작업 수행
    time.Sleep(2 * time.Second)
}
// Process: 2.001s

